config.script:
// 评估API返回数据的完整性和质量
let raw = step_2.to_string();
let data = parse_json(raw);

let has_userId = data.userId != ();
let has_id = data.id != ();
let has_title = data.title != ();
let has_body = data.body != ();

let title_len = if has_title { data.title.len } else { 0 };
let body_len = if has_body { data.body.len } else { 0 };
let fields_ok = if has_userId && has_id && has_title && has_body { 4 } else { 0 };

// 质量评分: 字段完整度60分 + 内容长度40分
let quality = if fields_ok >= 4 { 60.0 + (if title_len > 5 { 20.0 } else { 0.0 }) + (if body_len > 50 { 20.0 } else { 0.0 }) } else { 20.0 };
let level = if quality >= 80 { "优秀" } else if quality >= 60 { "合格" } else { "不合格" };

#{ 
    fields_ok: fields_ok, title_len: title_len, body_len: body_len,
    quality: quality, level: level, 
    title: data.title, userId: data.userId, id: data.id
}

